fig = figure(); %[output:81b7f652]
t = tiledlayout(fig,1,1); %[output:81b7f652]
ax = nexttile(t); %[output:81b7f652]
h = histogram(ax, TimeServed, Normalization="probability", BinWidth=5/60); %[output:81b7f652]
title(ax, "Time Customers Spent Being Served"); %[output:81b7f652]
xlabel(ax, "Time"); %[output:81b7f652]
ylabel(ax, "Probability"); %[output:81b7f652]
%[text] Set ranges on the axes.
ylim(ax, [0, 0.4]); %[output:81b7f652]
