fig = figure(); %[output:6241c498]
t = tiledlayout(fig,1,1); %[output:6241c498]
ax = nexttile(t); %[output:6241c498]
h = histogram(ax, CountReneged, Normalization="probability", BinMethod="integers"); %[output:6241c498]
